import React, { useState, useEffect, useMemo } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import {
  Sparkles, ArrowRight, Loader2, Check, Crown, Gift,
  Eye, Bot, Wrench, Users, Star, Shield, Zap, Award,
  ArrowLeft, ChevronRight, BadgeCheck
} from 'lucide-react';
import {
  waitlistSchema,
  WaitlistFormData,
  WaitlistResponse,
  joinWaitlist,
  getWaitlistCount,
} from '../services/waitlist';

interface WaitlistProps {
  onBack: () => void;
  onNavigate: (view: string) => void;
}

const Waitlist: React.FC<WaitlistProps> = ({ onBack, onNavigate }) => {
  // ── State ──
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitResult, setSubmitResult] = useState<WaitlistResponse | null>(null);
  const [waitlistCount, setWaitlistCount] = useState<number>(0);

  // ── URL param: ?ref= ──
  const refSource = useMemo(() => {
    try {
      const params = new URLSearchParams(window.location.search);
      const ref = params.get('ref');
      if (ref) {
        const allowed = ['direct', 'producthunt', 'twitter', 'linkedin', 'hackernews', 'reddit'] as const;
        if (allowed.includes(ref as typeof allowed[number])) {
          return ref as typeof allowed[number];
        }
      }
    } catch {
      // ignore
    }
    return 'direct' as const;
  }, []);

  // ── Form ──
  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<WaitlistFormData>({
    resolver: zodResolver(waitlistSchema),
    defaultValues: {
      name: '',
      email: '',
      company: '',
      source: refSource,
    },
  });

  // ── Fetch waitlist count on mount ──
  useEffect(() => {
    getWaitlistCount().then(setWaitlistCount).catch(() => {});
  }, []);

  // ── Submit handler ──
  const onSubmit = async (data: WaitlistFormData) => {
    setIsSubmitting(true);
    try {
      const result = await joinWaitlist({ ...data, source: refSource });
      setSubmitResult(result);
      if (result.success) {
        // Refresh count
        getWaitlistCount().then(setWaitlistCount).catch(() => {});
      }
    } catch {
      setSubmitResult({ success: false, error: 'Something went wrong. Please try again.' });
    } finally {
      setIsSubmitting(false);
    }
  };

  // ── Tier helpers ──
  const getTierInfo = (tier: 'top100' | 'top500' | null | undefined) => {
    if (tier === 'top100') {
      return {
        label: 'Founding Member',
        sublabel: 'Top 100',
        color: 'text-amber-400',
        bg: 'bg-amber-500/10',
        border: 'border-amber-500/20',
        icon: <Crown size={18} className="text-amber-400" />,
        perk: 'Lifetime 30% discount on all plans',
      };
    }
    if (tier === 'top500') {
      return {
        label: 'Early Adopter',
        sublabel: 'Top 500',
        color: 'text-purple-400',
        bg: 'bg-purple-500/10',
        border: 'border-purple-500/20',
        icon: <Star size={18} className="text-purple-400" />,
        perk: '3 months free on any plan',
      };
    }
    return null;
  };

  const top100Remaining = Math.max(0, 100 - waitlistCount);
  const top500Remaining = Math.max(0, 500 - waitlistCount);

  // ── Value prop cards ──
  const valueProps = [
    {
      icon: <Eye size={24} className="text-purple-400" />,
      title: 'AI Visibility Score',
      description: 'Measure how often AI engines like ChatGPT, Perplexity, and Gemini cite and recommend your brand.',
    },
    {
      icon: <Bot size={24} className="text-purple-400" />,
      title: 'Bot Monitoring',
      description: 'Track every AI crawler visiting your site in real-time. Know which bots index your content and how.',
    },
    {
      icon: <Wrench size={24} className="text-purple-400" />,
      title: 'Optimization Tools',
      description: 'Generate schema markup, structured content, and AI-friendly pages to boost your citation rate.',
    },
  ];

  return (
    <div className="w-full max-w-[1440px] mx-auto px-6 pt-16 pb-32 page-enter">

      {/* ── Back button ── */}
      <button
        onClick={onBack}
        className="flex items-center gap-2 text-gray-400 hover:text-white text-sm mb-8 transition-colors"
      >
        <ArrowLeft size={16} />
        Back
      </button>

      {/* ── HERO SECTION ── */}
      <div className="text-center mb-24 relative">
        {/* Ambient glow */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[700px] h-[500px] bg-purple-600/8 blur-[150px] rounded-full -z-10 pointer-events-none" />

        <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/[0.03] border border-white/[0.06] text-gray-400 text-xs font-medium tracking-wide uppercase mb-10">
          <Sparkles size={12} className="text-purple-400" />
          <span>Launching Soon</span>
        </div>

        <h1 className="text-4xl sm:text-5xl md:text-[4.5rem] font-sans font-bold tracking-tight text-white leading-[1.08] mb-8">
          Be the first to know<br />
          when AI recommends<br />
          <span className="text-purple-400">your brand</span>
        </h1>

        <p className="text-lg md:text-xl text-gray-500 max-w-2xl mx-auto leading-relaxed mb-6 font-light">
          Join as a founding member and lock in exclusive lifetime pricing.
          The first 100 members get a permanent 30% discount on all plans.
        </p>

        {/* Social proof counter */}
        {waitlistCount > 0 && (
          <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-white/[0.03] border border-white/[0.06] text-sm text-gray-400 mb-10">
            <Users size={14} className="text-purple-400" />
            <span>
              <span className="text-white font-semibold">{waitlistCount.toLocaleString()}</span> people already on the waitlist
            </span>
          </div>
        )}
      </div>

      {/* ── SIGNUP FORM / SUCCESS STATE ── */}
      <div className="max-w-lg mx-auto mb-32 relative">
        {/* Ambient glow */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[500px] h-[400px] bg-purple-600/[0.06] blur-[120px] rounded-full -z-10 pointer-events-none" />

        {submitResult?.success ? (
          /* ── Success state ── */
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-8 md:p-10 text-center">
            <div className="w-16 h-16 rounded-full bg-emerald-500/10 border border-emerald-500/20 flex items-center justify-center mx-auto mb-6">
              <Check size={28} className="text-emerald-400" />
            </div>

            <h2 className="text-2xl font-bold text-white mb-2">You're in!</h2>
            <p className="text-gray-400 mb-6">
              You're number <span className="text-white font-semibold">#{submitResult.signupNumber}</span> on the waitlist.
            </p>

            {/* Founding tier badge */}
            {(() => {
              const tier = getTierInfo(submitResult.foundingTier);
              if (!tier) return null;
              return (
                <div className={`inline-flex items-center gap-2.5 px-5 py-2.5 rounded-xl ${tier.bg} border ${tier.border} mb-6`}>
                  {tier.icon}
                  <div className="text-left">
                    <div className={`text-sm font-semibold ${tier.color}`}>
                      {tier.label} &mdash; {tier.sublabel}
                    </div>
                    <div className="text-xs text-gray-400">{tier.perk}</div>
                  </div>
                </div>
              );
            })()}

            <p className="text-sm text-gray-500 mt-4">
              We'll send you an email when we launch. Stay tuned!
            </p>
          </div>
        ) : (
          /* ── Signup form ── */
          <form
            onSubmit={handleSubmit(onSubmit)}
            className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-8 md:p-10"
          >
            <h2 className="text-xl font-semibold text-white mb-1">Join the waitlist</h2>
            <p className="text-sm text-gray-500 mb-8">Secure your spot and founding member pricing.</p>

            {/* Name */}
            <div className="mb-5">
              <label className="block text-sm font-medium text-gray-300 mb-1.5">
                Name <span className="text-red-400">*</span>
              </label>
              <input
                {...register('name')}
                type="text"
                placeholder="Your full name"
                className="w-full px-4 py-3 rounded-xl bg-white/[0.04] border border-white/[0.08] text-white placeholder-gray-600 text-sm focus:outline-none focus:border-purple-500/50 focus:ring-1 focus:ring-purple-500/30 transition-all"
              />
              {errors.name && (
                <p className="text-xs text-red-400 mt-1.5">{errors.name.message}</p>
              )}
            </div>

            {/* Email */}
            <div className="mb-5">
              <label className="block text-sm font-medium text-gray-300 mb-1.5">
                Email <span className="text-red-400">*</span>
              </label>
              <input
                {...register('email')}
                type="email"
                placeholder="you@company.com"
                className="w-full px-4 py-3 rounded-xl bg-white/[0.04] border border-white/[0.08] text-white placeholder-gray-600 text-sm focus:outline-none focus:border-purple-500/50 focus:ring-1 focus:ring-purple-500/30 transition-all"
              />
              {errors.email && (
                <p className="text-xs text-red-400 mt-1.5">{errors.email.message}</p>
              )}
            </div>

            {/* Company (optional) */}
            <div className="mb-8">
              <label className="block text-sm font-medium text-gray-300 mb-1.5">
                Company <span className="text-gray-600">(optional)</span>
              </label>
              <input
                {...register('company')}
                type="text"
                placeholder="Your company name"
                className="w-full px-4 py-3 rounded-xl bg-white/[0.04] border border-white/[0.08] text-white placeholder-gray-600 text-sm focus:outline-none focus:border-purple-500/50 focus:ring-1 focus:ring-purple-500/30 transition-all"
              />
              {errors.company && (
                <p className="text-xs text-red-400 mt-1.5">{errors.company.message}</p>
              )}
            </div>

            {/* Hidden source field */}
            <input type="hidden" {...register('source')} />

            {/* Error message */}
            {submitResult && !submitResult.success && (
              <div className="mb-6 px-4 py-3 rounded-xl bg-red-500/10 border border-red-500/20 text-sm text-red-400">
                {submitResult.error}
              </div>
            )}

            {/* Submit */}
            <button
              type="submit"
              disabled={isSubmitting}
              className="btn-gradient w-full flex items-center justify-center gap-2.5 text-base py-3.5 shadow-lg shadow-purple-600/20 hover:shadow-purple-600/30 disabled:opacity-60 disabled:cursor-not-allowed"
            >
              {isSubmitting ? (
                <>
                  <Loader2 size={18} className="animate-spin" />
                  Joining...
                </>
              ) : (
                <>
                  Join the Waitlist <ArrowRight size={18} />
                </>
              )}
            </button>

            <p className="text-xs text-gray-600 text-center mt-4">
              No spam, ever. Unsubscribe anytime.
            </p>
          </form>
        )}
      </div>

      {/* ── VALUE PROPOSITION CARDS ── */}
      <div className="max-w-5xl mx-auto mb-32">
        <div className="text-center mb-12">
          <h2 className="text-2xl md:text-3xl font-semibold tracking-tight text-white mb-4">
            What you'll get access to
          </h2>
          <p className="text-gray-500 max-w-2xl mx-auto text-[15px] leading-relaxed">
            CitedBy.ai is the first platform dedicated to Answer Engine Optimization.
            Measure, monitor, and improve how AI engines talk about your brand.
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
          {valueProps.map((prop, i) => (
            <div
              key={i}
              className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6 md:p-7 hover:bg-white/[0.05] hover:border-white/[0.08] transition-all duration-200"
            >
              <div className="w-12 h-12 rounded-xl bg-purple-500/10 border border-purple-500/20 flex items-center justify-center mb-5">
                {prop.icon}
              </div>
              <h3 className="text-lg font-semibold text-white mb-2">{prop.title}</h3>
              <p className="text-[14px] text-gray-500 leading-relaxed">{prop.description}</p>
            </div>
          ))}
        </div>
      </div>

      {/* ── FOUNDING MEMBER REWARDS ── */}
      <div className="max-w-4xl mx-auto mb-32">
        <div className="text-center mb-12">
          <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/[0.03] border border-white/[0.06] text-gray-400 text-xs font-medium tracking-wide uppercase mb-6">
            <Gift size={12} className="text-amber-400" />
            <span>Founding Member Rewards</span>
          </div>
          <h2 className="text-2xl md:text-3xl font-semibold tracking-tight text-white mb-4">
            Early supporters get exclusive perks
          </h2>
          <p className="text-gray-500 max-w-xl mx-auto text-[15px] leading-relaxed">
            The earlier you sign up, the bigger the reward. These tiers are first come, first served and cannot be unlocked later.
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
          {/* Tier 1: Top 100 */}
          <div className="bg-white/[0.03] border border-amber-500/20 rounded-2xl p-7 ring-1 ring-amber-500/[0.07] relative overflow-hidden">
            {/* Ambient */}
