            <div className="relative z-10">
              <span className="inline-flex items-center gap-2 px-3 py-1.5 rounded-lg bg-amber-500/10 border border-amber-500/20 text-[12px] font-semibold text-amber-400 uppercase tracking-wider mb-5">
                <Crown size={13} />
                Founding Member
              </span>
              <h3 className="text-xl font-bold text-white mb-2">Top 100</h3>
              <p className="text-[14px] text-gray-400 leading-relaxed mb-5">
                The first 100 people on the waitlist earn permanent founding member status.
              </p>
              <div className="space-y-3 mb-6">
                <div className="flex items-center gap-2.5 text-sm text-gray-300">
                  <Check size={15} className="text-amber-400 shrink-0" />
                  <span>Lifetime <span className="text-white font-semibold">30% discount</span> on all plans</span>
                </div>
                <div className="flex items-center gap-2.5 text-sm text-gray-300">
                  <Check size={15} className="text-amber-400 shrink-0" />
                  <span>Founding Member badge on profile</span>
                </div>
                <div className="flex items-center gap-2.5 text-sm text-gray-300">
                  <Check size={15} className="text-amber-400 shrink-0" />
                  <span>Priority access to new features</span>
                </div>
                <div className="flex items-center gap-2.5 text-sm text-gray-300">
                  <Check size={15} className="text-amber-400 shrink-0" />
                  <span>Direct feedback channel with founders</span>
                </div>
              </div>
              {/* Remaining spots */}
              <div className="flex items-center justify-between px-4 py-3 rounded-xl bg-amber-500/[0.06] border border-amber-500/[0.12]">
                <span className="text-[13px] text-gray-400">Spots remaining</span>
                <span className="text-sm font-bold text-amber-400">
                  {top100Remaining > 0 ? `${top100Remaining} / 100` : 'Sold out'}
                </span>
              </div>
            </div>
          </div>

          {/* Tier 2: Top 500 */}
          <div className="bg-white/[0.03] border border-purple-500/20 rounded-2xl p-7 ring-1 ring-purple-500/[0.07] relative overflow-hidden">
            {/* Ambient */}
            <div className="absolute top-0 right-0 w-32 h-32 bg-purple-500/[0.06] blur-[60px] rounded-full -z-0 pointer-events-none" />
            <div className="relative z-10">
              <span className="inline-flex items-center gap-2 px-3 py-1.5 rounded-lg bg-purple-500/10 border border-purple-500/20 text-[12px] font-semibold text-purple-400 uppercase tracking-wider mb-5">
                <Star size={13} />
                Early Adopter
              </span>
              <h3 className="text-xl font-bold text-white mb-2">Top 500</h3>
              <p className="text-[14px] text-gray-400 leading-relaxed mb-5">
                Sign up in the first 500 and get a generous head start when we launch.
              </p>
              <div className="space-y-3 mb-6">
                <div className="flex items-center gap-2.5 text-sm text-gray-300">
                  <Check size={15} className="text-purple-400 shrink-0" />
                  <span><span className="text-white font-semibold">3 months free</span> on any plan</span>
                </div>
                <div className="flex items-center gap-2.5 text-sm text-gray-300">
                  <Check size={15} className="text-purple-400 shrink-0" />
                  <span>Early Adopter badge on profile</span>
                </div>
                <div className="flex items-center gap-2.5 text-sm text-gray-300">
                  <Check size={15} className="text-purple-400 shrink-0" />
                  <span>Beta access before public launch</span>
                </div>
                <div className="flex items-center gap-2.5 text-sm text-gray-300">
                  <Check size={15} className="text-purple-400 shrink-0" />
                  <span>200 bonus credits at launch</span>
                </div>
              </div>
              {/* Remaining spots */}
              <div className="flex items-center justify-between px-4 py-3 rounded-xl bg-purple-500/[0.06] border border-purple-500/[0.12]">
                <span className="text-[13px] text-gray-400">Spots remaining</span>
                <span className="text-sm font-bold text-purple-400">
                  {top500Remaining > 0 ? `${top500Remaining} / 500` : 'Sold out'}
                </span>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* ── BOTTOM CTA ── */}
      {!submitResult?.success && (
        <div className="text-center mb-16">
          <p className="text-gray-500 text-[15px] mb-6">
            Don't miss your founding member spot.
          </p>
          <button
            onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}
            className="btn-gradient text-base px-8 py-3.5 flex items-center gap-2.5 mx-auto shadow-lg shadow-purple-600/20 hover:shadow-purple-600/30"
          >
            Join Now <ArrowRight size={18} />
          </button>
        </div>
      )}
    </div>
  );
};

export default Waitlist;

